sql:
SELECT COUNT(*) AS broadcast_count
FROM broadcasts
WHERE category = 'News';

SELECT broadcast_id
FROM broadcasts
WHERE category = 'News';

SELECT snippet
FROM broadcasts
WHERE broadcast_id = 1;

